void insert(node_t **head, int val) {
  node_t *n = malloc(sizeof(node_t));
  n->val = val; n->next = *head; *head = n;
}

void free_list(node_t *curr) {
  if (curr == NULL) return;
  free_list(curr->next);
  if (curr->data) free(curr->data);
  free(curr);
}

